import{_ as t,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"30. Compensation Make Up Pay","description":"","frontmatter":{"title":"30. Compensation Make Up Pay","eba":"Mental Health Services 2024-2028","topics":["wages","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/wages/30-compensation-make-up-pay.md","filePath":"ebas/mental-health/common-terms/wages/30-compensation-make-up-pay.md"}'),r={name:"ebas/mental-health/common-terms/wages/30-compensation-make-up-pay.md"};function i(p,e,s,m,l,y){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_30-compensation-make-up-pay" tabindex="-1">30. Compensation Make Up Pay <a class="header-anchor" href="#_30-compensation-make-up-pay" aria-label="Permalink to &quot;30. Compensation Make Up Pay&quot;">​</a></h1><p>Note: This clause was previously titled Accident Make-Up Pay.</p><p><strong>30.1</strong> Entitlement to compensation make-up pay An Employee receiving compensation for incapacity under the WIRC Act will be entitled to compensation make up pay from the Employer who is liable to pay compensation in accordance with this clause (including pro rata for any part of the week).</p><p><strong>30.2</strong> Definitions</p><p><strong>(a)</strong> Compensation make-up pay means:</p><p><strong>(i)</strong> In the case of an Employee with no current work capacity, a payment equal to the Scheme-determined Pre-Injury Average Weekly Earnings, less the amount of weekly compensation.</p><p><strong>(ii)</strong> In the case of an Employee with a current work capacity, a payment equal to the Scheme-determined Pre-Injury Average Weekly Earnings less the amount of weekly compensation and less the average amount the Employee is earning in suitable employment.</p><p><strong>(b)</strong> Injury under this clause has the same meaning as workers&#39; compensation legislation and includes a disease contracted by an Employee in the course of the Employee&#39;s employment.</p><p><strong>(c)</strong> Scheme-determined Pre-Injury Average Weekly Earnings (or PIAWE) is the amount determined by the WorkCover Agent or WorkSafe Victoria under the WIRC Act to be the Employee&#39;s PIAWE for the purposes of the claim.</p><p><strong>30.3</strong> Maximum payment The maximum period or aggregate periods of compensation make-up pay to be made up by an Employer will be a total of 39 weeks for any one injury.</p><p><strong>30.4</strong> Compensation make-up pay will not apply in some circumstances Compensation make-up pay in accordance with this clause will not apply:</p><p><strong>(a)</strong> in respect of any injury during the first five days of incapacity, except where the Employee contracts an infectious disease for which the Employee is entitled to receive worker compensation in which case compensation make-up pay will apply from the first day of the incapacity</p><p><strong>(b)</strong> to any incapacity occurring during the first two weeks of employment unless that incapacity continues beyond the first two weeks in which case Compensation make-up pay will apply only to the period of incapacity after the first two weeks; or</p><p><strong>(c)</strong> during any period when the Employee fails to comply with the requirements of the WIRC Act with regard to examination be a medical practitioner</p><p><strong>(d)</strong> where the Injury for which the Employee is receiving weekly compensation payments is a pre-existing Injury that work has contributed to by way of recurrence, aggravation, acceleration, exacerbation or deterioration, and the Employee failed to disclose the Injury on engagement:</p><p><strong>(i)</strong> following a request to do so by the Employer</p><p><strong>(ii)</strong> the Employer providing the Employee details of the requirements of the position; and</p><p><strong>(iii)</strong> where the Employee knew, or ought to have known, that the nature of the Injury may impact on the ability of the Employee to undertake the work.</p><p><strong>(e)</strong> where in accordance with the WIRC Act, a medical practitioner provides information to an Employer of an Employee&#39;s fitness for work or specifies work for which an Employee has a capacity and that work is made available by an Employer but not commenced by an Employee</p><p><strong>(f)</strong> when the claim has been ceased or redeemed in accordance with the WIRC Act; or</p><p><strong>(g)</strong> in respect of any paid leave of absence.</p><p><strong>30.5</strong> Reduction of compensation</p><p>Where an Employee receives a weekly payment under this clause and subsequently that payment is reduced pursuant to the WIRC Act, that reduction will not render the Employer liable to increase the amount of Compensation make-up pay in respect of that injury.</p><p><strong>30.6</strong> Termination of Employment</p><p><strong>(a)</strong> Termination of Employment by the Employee Compensation make-up pay ceases where the Employee terminates their employment except:</p><p><strong>(i)</strong> if an Employee with partial incapacity cannot obtain suitable employment from the Employer but such alternative employment is available with another Employer; and</p><p><strong>(ii)</strong> the Employee, if required, provides evidence to the Employer of the continuing payment of weekly compensation payments.</p><p><strong>(b)</strong> Termination of Employment by the Employer An entitlement to Compensation make-up pay does not cease on termination where the Employer terminates the Employee&#39;s employment, except where the termination is for serious and wilful misconduct.</p><p><strong>30.7</strong> Civil damage claims</p><p><strong>(a)</strong> An Employee receiving or who received Compensation make-up pay must advise the Employer of any action or claim the Employee may institute for damages. If requested, the Employee will provide an authority to the Employer entitling the Employer to a charge upon any money payable pursuant to any judgment or settlement on that injury.</p><p><strong>(b)</strong> Where an Employee obtains a judgment or settlement for damages in respect of an Injury for which the Employee received Compensation make-up pay, the Employer&#39;s liability to pay Compensation make-up pay ceases from the date of such judgment or settlement where the damages are not reduced (in whole or part) by the Compensation make-up pay paid by the Employer. Where damages from a judgment or settlement are not reduced to take into account Compensation make-up pay paid by the Employer (in whole or part), the Employee must repay the Employer the Compensation make-up pay to the extent the damages were not reduced.</p><p><strong>(c)</strong> Where an Employee obtains a judgment or settlement for damages against a person other than the Employer in respect of an Injury for which the Employee received Compensation make-up pay, the Employer&#39;s liability to pay Compensation make-up pay will cease from the date of such judgment or settlement where the damages are not reduced (in whole or part) by the amount of Compensation make-up pay made by the Employer. The Employee must pay to their Employer any amount of Compensation make-up pay already received in respect of that Injury by which the judgment or settlement has not been so reduced.</p><p><strong>30.8</strong> Supplementary Accident Make Up Pay Employees who as at 19 December 1997 were Employees of the Department and eligible for a commuted allowance shall while on paid accident compensation leave, continue to receive commuted allowance up to a maximum period of 26 weeks or an aggregate period of 131 days from the date of the injury.</p>',33)])])}const u=t(r,[["render",i]]);export{h as __pageData,u as default};
